textOptions.schema:
{
  "type": "object",
  "properties": {
    "score": {
      "type": "number",
      "description": "Lead score from 0 to 100"
    },
    "tier": {
      "type": "string",
      "enum": ["HOT", "WARM", "COLD", "DISCARDED"],
      "description": "Lead tier based on score"
    },
    "summary": {
      "type": "string",
      "description": "2 sentence agent briefing about the lead"
    },
    "recommended_action": {
      "type": "string",
      "description": "Specific next step for the agent"
    },
    "personalized_opener": {
      "type": "string",
      "description": "1 warm sentence to open the lead email"
    }
  },
  "required": ["score", "tier", "summary", "recommended_action", "personalized_opener"],
  "additionalProperties": false
}

values.content:
=Write personalized emails for this real estate lead.

QUALIFICATION RESULTS:
- Tier:{{ $json.fields.Tier }}
- Score: {{ $json.fields.Score }}/100
- AI Summary: {{ $json.fields['AI Summary'] }}
- Recommended Action: {{ $json.fields['Recommended Action'] }}

LEAD PERSONAL DETAILS:
- Name: {{ $json.fields['Full Name'] }}
- Email: {{ $('Lead Info').item.json.fields['Email Address'] }}
- Intent: {{ $('Update CRM after AI Qualification').item.json.fields.Intent }}
- Biggest Concern: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json['What is your biggest concern right now?'], 'Not provided') }}
- Best Contact Time: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json['Best time to contact you?'], 'Not provided') }}

BUYER DETAILS (if applicable):
- Area Interested: {{ $if($('Update CRM Pipeline: Buyer Info').isExecuted, $('Update CRM Pipeline: Buyer Info').item.json.fields.Area, 'Not applicable') }}
- Budget: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json.budget, 'Not applicable') }}
- Pre-Approved: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json.pre_approved, 'Not applicable') }}
- Buy Timeline: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json.buy_timeline, 'Not applicable') }}
- Working With Agent: {{ $if($('Buyer Information').isExecuted, $('Buyer Information').item.json.working_with_agent, 'Not applicable') }}

SELLER DETAILS (if applicable):
- Property Address: {{ $json.fields['Property Address'] || 'Not applicable' }}
- Property Type: {{ $json.fields['Property Type'] || 'Not applicable' }}
- Sell Timeline: {{ $json.fields['Sell Timeline'] || 'Not applicable' }}
- Listed Status: {{ $json.fields['Listed Status'] || 'Not applicable' }}
- Seriousness: {{ $json.fields.Seriousness || 'Not applicable' }}

EXPLORING DETAILS (if applicable):
- Curiosity: {{ $json.fields.Curiosity || 'Not applicable' }}
- Future Timeline: {{ $json.fields['Future Timeline'] || 'Not applicable' }}

INSTRUCTIONS:
1. Write EMAIL 1 for the lead based on their intent
   and tier. Make it feel personal and relevant to
   their exact situation. If they are a buyer mention
   their area and budget. If seller mention their
   property. If exploring be encouraging and curious.

2. Write EMAIL 2 for the realtor only if tier is
   HOT or WARM. Structure it as a clear briefing
   with all lead details, score, tier and the
   recommended next action with urgency level.
   If COLD write: NO_REALTOR_EMAIL

textOptions.schema:
{
  "type": "object",
  "properties": {
    "lead_subject": {
      "type": "string",
      "description": "Subject line for the lead email"
    },
    "lead_email": {
      "type": "string",
      "description": "Email body for the lead"
    },
    "realtor_subject": {
      "type": "string",
      "description": "Subject line for the realtor email or NO_REALTOR_EMAIL if COLD"
    },
    "realtor_email": {
      "type": "string",
      "description": "Email body for the realtor or NO_REALTOR_EMAIL if COLD"
    }
  },
  "required": [
    "lead_subject",
    "lead_email",
    "realtor_subject",
    "realtor_email"
  ],
  "additionalProperties": false
}
